ame" required>                    </div>                    <div class="col-md-6 mb-2">                        <label for="last_name" class="form-label">Last Name <span class="text-danger">*</span></label>                        <input type="text" class="form-control" id="last_name" name="last_name" required>                    </div>                    <div class="col-md-6 mb-2">                        <label for="mobile" class="form-label">Phone <span class="text-danger">*</span></label>                        <input type="number" class="form-control" id="mobile" name="mobile" required>                    </div>                    <div class="col-md-6 mb-2">                        <label for="email" class="form-label">Email <span class="text-danger">*</span></label>                        <input type="email" class="form-control" id="email" name="email" required>                    </div>                                        <div class="col-12 mb-2">                        <h3>Payment Method</h3>                                                <div class="form-check mb-2">                            <input class="form-check-input" type="radio" name="payment_method" id="payment_method" value="stripe" checked>                                                        <div class="card-icons">                                <img src="{{ asset('frontend/images/credit-card-image2.png') }}" alt="Visa">                                                            </div>                        </div>                                            </div>                                        <div class="col-12 mb-2">                        <div class="form-check">                            <div id="card-element"></div>                            <div id="card-errors" role="alert"></div>                        </div>                    </div>                                        <div class="col-12 mb-2">                        <input type="hid