ent-Type": "application/json",                        "X-CSRF-TOKEN": "{{ csrf_token() }}"                    },                    body: JSON.stringify({                        payment_method_id: paymentMethod.id,                        amount: document.getElementById("order_amount").value,                        first_name: document.getElementById("first_name").value,                        last_name: document.getElementById("last_name").value,                        mobile: document.getElementById("mobile").value,                        email: document.getElementById("email").value,                        payment_method: document.querySelector('input[name="payment_method"]:checked').value,                    })                })                .then(response => response.json())                .then(data => {                    if (data.error) {                        alert("Payment failed: " + data.error);                    } else {                        console.log(data);                        if(data.paymentIntent==0){                            window.location.href = "{{ url('services/0/0') }}"; // Redirect on success                        }else{                            window.location.href = "{{ route('booking-success') }}"; // Redirect on success                        }                        //alert("Payment successful!");                    }                });            }        });    </script> @endsection